<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="utf-8">
<title>Maze Escape — 24 Trémaux Bots Discover the Exit</title>
<meta name="viewport" content="width=device-width, initial-scale=1">
<style>
  html,body{margin:0;padding:0}
  body{min-height:100vh;background:#0d1220;color:#e9eef7;
       font-family:system-ui,-apple-system,"Segoe UI",Roboto,Arial,sans-serif;
       display:flex;flex-direction:column;align-items:center;padding:18px 12px 28px}
  h1{font-size:18px;font-weight:650;letter-spacing:.4px;margin:2px 0 12px;text-align:center}
  #hud{display:flex;gap:10px;align-items:stretch;flex-wrap:wrap;justify-content:center;margin-bottom:12px}
  .pill{background:#171f31;border:1px solid #2b3752;border-radius:10px;padding:9px 16px;
        font-size:15px;font-variant-numeric:tabular-nums;min-width:132px;text-align:center;
        display:flex;align-items:center;justify-content:center}
  #timer{color:#7fd4ff}
  #completed{color:#8ef0b2}
  #reset{background:#3b82f6;border:none;color:#fff;font-size:15px;font-weight:600;
         border-radius:10px;padding:9px 20px;cursor:pointer}
  #reset:hover{background:#2f72e0}
  #reset:active{transform:translateY(1px)}
  #maze{background:#080b13;border:1px solid #2b3752;border-radius:12px;padding:10px;
        line-height:0;box-shadow:0 10px 30px rgba(0,0,0,.45)}
  #board{display:block;border-radius:4px}
  #status{margin-top:10px;font-size:13px;color:#93a3c2;min-height:17px;text-align:center}
</style>
</head>
<body>
<h1>Perfect Maze · 24 Trémaux Bots Discover the Exit</h1>
<div id="hud">
  <div class="pill" id="timer">Time: 0 ticks</div>
  <div class="pill" id="completed">Completed: 0 / 24</div>
  <button id="reset" type="button">Reset</button>
</div>
<div id="maze"><canvas id="board" width="584" height="584"></canvas></div>
<div id="status"></div>

<script>
(function(){
"use strict";

/* ================= deterministic PRNG ================= */
function mulberry32(a){
  return function(){
    a|=0; a=(a+0x6D2B79F5)|0;
    var t=Math.imul(a^(a>>>15),1|a);
    t=(t+Math.imul(t^(t>>>7),61|t))^t;
    return ((t^(t>>>14))>>>0)/4294967296;
  };
}

/* ================= config ================= */
var ROWS=20, COLS=20, NBOTS=24;
var CELL=28, PAD=12;
var W=PAD*2+COLS*CELL, H=PAD*2+ROWS*CELL;
var TICKS_PER_SEC=14;
var DIRS=[
  {dr:-1,dc:0, k:'n', op:'s'},
  {dr:0, dc:1, k:'e', op:'w'},
  {dr:1, dc:0, k:'s', op:'n'},
  {dr:0,dc:-1, k:'w', op:'e'}
];
function key(r,c){ return r*COLS+c; }

/* ================= perfect maze generation (recursive backtracker) ================= */
function genMaze(rng){
  var w=[], r, c;
  for(r=0;r<ROWS;r++){ var row=[]; for(c=0;c<COLS;c++) row.push({n:true,e:true,s:true,w:true}); w.push(row); }
  var vis=[], stack=[{r:0,c:0}];
  for(r=0;r<ROWS;r++){ vis.push(new Array(COLS).fill(false)); }
  vis[0][0]=true;
  while(stack.length){
    var cur=stack[stack.length-1];
    var opts=[];
    for(var d=0;d<4;d++){
      var nr=cur.r+DIRS[d].dr, nc=cur.c+DIRS[d].dc;
      if(nr>=0&&nr<ROWS&&nc>=0&&nc<COLS&&!vis[nr][nc]) opts.push(d);
    }
    if(!opts.length){ stack.pop(); continue; }
    var dd=opts[(rng()*opts.length)|0];
    var r2=cur.r+DIRS[dd].dr, c2=cur.c+DIRS[dd].dc;
    w[cur.r][cur.c][DIRS[dd].k]=false;
    w[r2][c2][DIRS[dd].op]=false;
    vis[r2][c2]=true;
    stack.push({r:r2,c:c2});
  }
  return w;
}

/* farthest cell from src (used ONLY at build time to place the exit; bots never see this) */
function farthestCell(w,src){
  var dist=[], r, c;
  for(r=0;r<ROWS;r++) dist.push(new Array(COLS).fill(-1));
  var q=[{r:src.r,c:src.c}]; dist[src.r][src.c]=0;
  for(var i=0;i<q.length;i++){
    var cur=q[i];
    for(var d=0;d<4;d++){
      if(w[cur.r][cur.c][DIRS[d].k]) continue;
      var nr=cur.r+DIRS[d].dr, nc=cur.c+DIRS[d].dc;
      if(dist[nr][nc]===-1){ dist[nr][nc]=dist[cur.r][cur.c]+1; q.push({r:nr,c:nc}); }
    }
  }
  var best={r:src.r,c:src.c}, bd=0;
  for(r=0;r<ROWS;r++) for(c=0;c<COLS;c++)
    if(dist[r][c]>bd){ bd=dist[r][c]; best={r:r,c:c}; }
  return best;
}

/* all 24 permutations of [N,E,S,W] -> genuinely different exploration preferences */
function allPermutations(){
  var out=[];
  (function rec(prefix,rest){
    if(!rest.length){ out.push(prefix); return; }
    for(var i=0;i<rest.length;i++)
      rec(prefix.concat(rest[i]), rest.slice(0,i).concat(rest.slice(i+1)));
  })([],[0,1,2,3]);
  return out;
}

/* ================= game state ================= */
var state={ seed:0, walls:null, spawn:{r:0,c:0}, exit:{r:0,c:0}, bots:[], elapsed:0, done:false };

function botColor(i){
  var hue=Math.round((i*137.508)%360);
  var light=(i%2===0)?56:46;
  return 'hsl('+hue+',82%,'+light+'%)';
}

function makeBot(idx,order,spawn){
  var ang=idx*2.399963229728653; // golden angle -> spread out visually when sharing a cell
  var rad=CELL*0.16;
  return {
    id:idx,
    order:order.slice(),
    color:botColor(idx),
    ox:Math.cos(ang)*rad, oy:Math.sin(ang)*rad,
    stack:[{r:spawn.r,c:spawn.c}],               // DFS path from spawn to current cell
    visited:new Set([key(spawn.r,spawn.c)]),      // private memory
    deadSet:new Set(),                            // private memory of dead branches
    fx:spawn.c, fy:spawn.r,                       // smooth render position (cell units)
    path:[{r:spawn.r,c:spawn.c}],
    deadEnds:[],
    finishTick:null
  };
}

function reset(seed){
  var s=(typeof seed==='number' && isFinite(seed)) ? (seed>>>0) : ((Math.random()*4294967296)>>>0);
  state.seed=s;
  var rng=mulberry32(s);
  state.walls=genMaze(rng);
  state.spawn={r:(rng()*ROWS)|0, c:(rng()*COLS)|0};
  state.exit=farthestCell(state.walls,state.spawn);
  var perms=allPermutations();
  for(var i=perms.length-1;i>0;i--){
    var j=(rng()*(i+1))|0, t=perms[i]; perms[i]=perms[j]; perms[j]=t;
  }
  state.bots=[];
  for(var b=0;b<NBOTS;b++) state.bots.push(makeBot(b,perms[b],state.spawn));
  state.elapsed=0;
  state.done=false;
  hudDirty=true;
  return s;
}

/* One bot move = one cell per tick.
 * Trémaux/DFS over the bot's PRIVATE knowledge only:
 *  - senses walls of the cell it stands in,
 *  - prefers unvisited passages in its own seeded direction order,
 *  - otherwise marks the cell dead and backtracks along its stack.
 * Each passage is therefore traversed at most twice (down once, back once). */
function stepBot(b){
  if(b.finishTick!==null) return;
  var stack=b.stack;
  if(!stack.length) return;
  var cur=stack[stack.length-1];
  var cw=state.walls[cur.r][cur.c];
  for(var i=0;i<4;i++){
    var d=b.order[i];
    if(cw[DIRS[d].k]) continue;                       // wall sensed in current cell
    var nr=cur.r+DIRS[d].dr, nc=cur.c+DIRS[d].dc;
    if(nr<0||nr>=ROWS||nc<0||nc>=COLS) continue;
    var k=key(nr,nc);
    if(b.visited.has(k)||b.deadSet.has(k)) continue;  // already explored / known dead
    stack.push({r:nr,c:nc});
    b.visited.add(k);
    b.path.push({r:nr,c:nc});
    if(nr===state.exit.r && nc===state.exit.c) b.finishTick=state.elapsed;
    return;
  }
  // dead end or fully explored branch -> record as dead and backtrack
  var ck=key(cur.r,cur.c);
  if(!b.deadSet.has(ck)){ b.deadSet.add(ck); b.deadEnds.push({r:cur.r,c:cur.c}); }
  stack.pop();
  if(stack.length){
    var p=stack[stack.length-1];
    b.path.push({r:p.r,c:p.c});                        // re-entered while backtracking
  }
}

function stepOnce(){
  if(state.done) return;                              // timer frozen after last arrival
  state.elapsed++;
  var bs=state.bots;
  for(var i=0;i<bs.length;i++) stepBot(bs[i]);
  var all=true;
  for(i=0;i<bs.length;i++) if(bs[i].finishTick===null){ all=false; break; }
  if(all) state.done=true;                            // freeze: elapsed never changes again
}

/* ================= public API ================= */
function tick(n){
  n=Math.floor(Number(n));
  if(!(n>0)) return;
  for(var i=0;i<n;i++) stepOnce();
  hudDirty=true;
}

window.game={
  tick:tick,
  reset:function(seed){ return reset(seed); },
  get elapsed(){ return state.elapsed; },
  get size(){ return {rows:ROWS, cols:COLS}; },
  get spawn(){ return {r:state.spawn.r, c:state.spawn.c}; },
  get exit(){ return {r:state.exit.r, c:state.exit.c}; },
  get seed(){ return state.seed; },
  walls:function(r,c){ var w=state.walls[r][c]; return {n:w.n, e:w.e, s:w.s, w:w.w}; },
  get bots(){ return state.bots; }
};

/* ================= rendering ================= */
var canvas=document.getElementById('board');
canvas.width=W; canvas.height=H;
var ctx=canvas.getContext('2d');
var timerEl=document.getElementById('timer');
var completedEl=document.getElementById('completed');
var statusEl=document.getElementById('status');

var hudDirty=true, lastTimer='', lastCompleted='', lastStatus='';
function updateHUD(){
  var done=0;
  for(var i=0;i<state.bots.length;i++) if(state.bots[i].finishTick!==null) done++;
  var tt='Time: '+state.elapsed+' ticks';
  var ct='Completed: '+done+' / '+NBOTS;
  var st=state.done
    ? 'All 24 bots found the exit — timer frozen at tick '+state.elapsed+'.  (seed '+state.seed+')'
    : 'Exploring: 24 independent Trémaux/DFS walkers, no map, no exit knowledge · seed '+state.seed;
  if(tt!==lastTimer){ timerEl.textContent=tt; lastTimer=tt; }
  if(ct!==lastCompleted){ completedEl.textContent=ct; lastCompleted=ct; }
  if(st!==lastStatus){ statusEl.textContent=st; lastStatus=st; }
}

function draw(){
  var r,c;
  ctx.fillStyle='#080b13';
  ctx.fillRect(0,0,W,H);

  ctx.fillStyle='rgba(127,212,255,0.10)';
  ctx.fillRect(PAD+state.spawn.c*CELL, PAD+state.spawn.r*CELL, CELL, CELL);
  ctx.fillStyle='rgba(110,240,160,0.14)';
  ctx.fillRect(PAD+state.exit.c*CELL, PAD+state.exit.r*CELL, CELL, CELL);

  ctx.strokeStyle='#cdd8ec';
  ctx.lineWidth=2.4;
  ctx.lineCap='square';
  ctx.beginPath();
  for(r=0;r<ROWS;r++){
    for(c=0;c<COLS;c++){
      var w=state.walls[r][c];
      var x=PAD+c*CELL, y=PAD+r*CELL;
      if(w.n){ ctx.moveTo(x,y); ctx.lineTo(x+CELL,y); }
      if(w.w){ ctx.moveTo(x,y); ctx.lineTo(x,y+CELL); }
      if(r===ROWS-1 && w.s){ ctx.moveTo(x,y+CELL); ctx.lineTo(x+CELL,y+CELL); }
      if(c===COLS-1 && w.e){ ctx.moveTo(x+CELL,y); ctx.lineTo(x+CELL,y+CELL); }
    }
  }
  ctx.stroke();

  var ex=PAD+(state.exit.c+0.5)*CELL, ey=PAD+(state.exit.r+0.5)*CELL;
  ctx.beginPath(); ctx.arc(ex,ey,CELL*0.30,0,Math.PI*2); ctx.fillStyle='#1fae5f'; ctx.fill();
  ctx.beginPath(); ctx.arc(ex,ey,CELL*0.13,0,Math.PI*2); ctx.fillStyle='#d6ffe7'; ctx.fill();

  var sx=PAD+(state.spawn.c+0.5)*CELL, sy=PAD+(state.spawn.r+0.5)*CELL;
  ctx.beginPath(); ctx.arc(sx,sy,CELL*0.20,0,Math.PI*2);
  ctx.strokeStyle='rgba(160,200,255,0.7)'; ctx.lineWidth=2; ctx.stroke();

  var rad=Math.max(3,CELL*0.15);
  for(var i=0;i<state.bots.length;i++){
    var b=state.bots[i];
    var px=PAD+(b.fx+0.5)*CELL+b.ox;
    var py=PAD+(b.fy+0.5)*CELL+b.oy;
    ctx.beginPath();
    ctx.arc(px,py,rad,0,Math.PI*2);
    ctx.fillStyle=b.color;
    ctx.fill();
    ctx.lineWidth=1;
    ctx.strokeStyle='rgba(0,0,0,0.55)';
    ctx.stroke();
  }
}

/* ================= main loop: sim ticks + smooth interpolation ================= */
var last=performance.now(), acc=0;
function frame(now){
  var dt=(now-last)/1000; last=now;
  if(dt>0.25) dt=0.25;
  if(!state.done){
    acc+=dt*TICKS_PER_SEC;
    while(acc>=1){ acc-=1; stepOnce(); hudDirty=true; }
  } else acc=0;

  var step=TICKS_PER_SEC*1.3*dt; // constant-speed pursuit -> smooth, corridor-centered motion
  for(var i=0;i<state.bots.length;i++){
    var b=state.bots[i];
    var t=b.stack[b.stack.length-1];
    var dx=t.c-b.fx, dy=t.r-b.fy;
    var d=Math.sqrt(dx*dx+dy*dy);
    if(d<=step || d===0){ b.fx=t.c; b.fy=t.r; }
    else { b.fx+=dx/d*step; b.fy+=dy/d*step; }
  }

  if(hudDirty){ updateHUD(); hudDirty=false; }
  draw();
  requestAnimationFrame(frame);
}

document.getElementById('reset').addEventListener('click',function(){ reset(); acc=0; });

reset();
requestAnimationFrame(frame);

})();
</script>
</body>
</html>
